        while (running) {
            view.displayMainMenuBanner();
            int choice = view.getMenuSelection();
            switch (choice) {
                case 1 -> displayOrders();
                case 2 -> addOrder();
                case 3 -> editOrder();
                case 4 -> removeOrder();
                case 5 -> exportData();
                case 6 -> {
                    view.displayExitMessage();
                    running = false;
                }
            }
        }
    }

    // display orders

    private void displayOrders() {
        view.displayDisplayOrdersBanner();
